INSERT INTO `tests` VALUES (3,'2025-05-30 17:36:29.602968','admin','123123',1,'123',_binary '','Reading VIP 01','READING_ONLY','EASY'),(4,'2025-05-30 17:59:51.864504','admin','đề thi gồm 10 câu part 5 được chắt lọc  hehe',10,'',_binary '','Part 5 vip ','READING_ONLY','HARD'),(5,'2025-05-30 18:01:08.157430','admin','Đề thi gồm 10 câu part 5 được chắt lọc ',1,'',_binary '','part 5 vip 2','FULL','EASY'),(6,'2025-05-30 18:02:21.843391','admin','Gồm 10 câu part 5 được chắt lọc ',10,'',_binary '','Part 5 vip 3','READING_ONLY','MEDIUM'),(7,'2025-05-30 18:03:46.083441','admin','Gồm 2 đoạn văn Part 6',15,'',_binary '','Part 6 VIP','READING_ONLY','MEDIUM'),(8,'2025-05-30 18:04:19.411187','admin','Gồm 2 đoạn văn Part 6',15,'',_binary '','Part 6 VIP	2','READING_ONLY','MEDIUM'),(9,'2025-05-30 18:04:49.204304','admin','Gồm 2 đoạn văn Part 6',15,'',_binary '','Part 6 VIP	3','FULL','MEDIUM'),(12,'2025-06-01 16:45:19.002428','admin','Verb \'to be\' (am/is/are) - Present Simple',120,'Động từ \"to be\" có nghĩa là \"thì\", \"là\", \"ở\". Nó có 3 dạng ở hiện tại, được chia theo chủ ngữ:\n\nI → am\n\nVí dụ: I **am** a student. (Tôi là một học sinh.)\nHe / She / It (và danh từ số ít - một người/vật) → is\n\nVí dụ: He **is** a doctor. (Anh ấy là một bác sĩ.)\nVí dụ: The book **is** new. (Quyển sách thì mới.)\nYou / We / They (và danh từ số nhiều - hai người/vật trở lên) → are\n\nVí dụ: They **are** friends. (Họ là những người bạn.)\nVí dụ: The books **are** new. (Những quyển sách thì mới.)\nPhủ định và Câu hỏi:\n\nPhủ định: Thêm not vào sau am/is/are. (Ví dụ: She **is not** here.)\nCâu hỏi: Đưa Am/Is/Are lên đầu câu. (Ví dụ: **Is** she here?)',_binary '','Verb \'to be\' (am/is/are) - Present Simple','GRAMMAR_ONLY','EASY'),(13,'2025-06-02 06:40:42.617541','admin','Articles (a/an)',120,'\"a\" và \"an\" đều có nghĩa là \"một\". Quy tắc sử dụng chúng dựa vào âm thanh của từ đứng ngay sau nó.\n\nDùng an trước một âm nguyên âm (các âm bắt đầu bằng u, e, o, a, i).\n\nVí dụ: an apple, an egg, an orange.\nDùng a trước một âm phụ âm (tất cả các âm còn lại).\n\nVí dụ: a book, a cat, a dog.',_binary '','Articles (a/an)','GRAMMAR_ONLY','EASY'),(16,'2025-06-02 06:56:58.383547','admin','Plural Nouns (simple -s)',120,'Lý Thuyết: Danh từ Số nhiều (Plural Nouns) - Quy tắc thêm \"-s\"\nTrong tiếng Anh, danh từ được chia thành hai dạng chính: danh từ số ít (singular noun) và danh từ số nhiều (plural noun).\n\nDanh từ số ít: Dùng để chỉ một sự vật, con vật, hoặc người.\nVí dụ: a book (một quyển sách), a cat (một con mèo).\nDanh từ số nhiều: Dùng để chỉ từ hai trở lên sự vật, con vật, hoặc người.\nVí dụ: two books (hai quyển sách), many cats (nhiều con mèo).\nĐể chuyển một danh từ từ dạng số ít sang số nhiều, chúng ta có nhiều quy tắc khác nhau. Tuy nhiên, quy tắc cơ bản và phổ biến nhất là thêm \"-s\" vào cuối danh từ.\n\nQuy tắc cơ bản: Thêm \"-s\"\nĐây là cách đơn giản và thông dụng nhất để tạo danh từ số nhiều.\n\nCách làm: Bạn chỉ cần thêm chữ cái -s vào cuối của hầu hết các danh từ số ít.\n\nCông thức:\n\nDanh từ số ít + s = Danh từ số nhiều',_binary '','Plural Nouns (simple -s)','GRAMMAR_ONLY','MEDIUM'),(17,'2025-06-02 09:43:01.946234','admin','Office and Business',120,'Office and Business',_binary '','Office and Business','VOCABULARY_ONLY','MEDIUM'),(18,'2025-06-02 09:54:28.872980','admin','Travel and Transportation',120,'Travel and Transportation',_binary '','Travel and Transportation','VOCABULARY_ONLY','MEDIUM'),(20,'2025-06-10 18:08:30.616859','admin','đề thi rút gọn 1 dành cho những người muốn mau chóng đánh giá trình độ của mình bằng những câu hỏi được chắt lọc',120,'',_binary '','đề thi rút gọn 1','MINI','MEDIUM'),(21,'2025-06-10 18:47:19.025757','admin','Đề gồm mỗi 4 phần nghe của từng part nghe',120,'',_binary '','Đề nghe mini 01','MINI','EASY'),(22,'2025-06-10 19:02:03.670940','admin','',30,'',_binary '','Mini test 01','MINI','EASY'),(23,'2025-06-25 08:25:11.369870','admin','',120,'',_binary '','	Greetings and Introductions','VOCABULARY_O